/// Promo module configuration
///
/// Use the builder pattern to configure and register this module:
///
/// ```text
/// let promo = PromoModule::builder()
///     .with_database(pool.clone())
///     .build()?;
///
/// // Unguarded full CRUD (trusted/admin); compose a guarded router for production.
/// let router = promo.all_crud_routes();
/// ```
pub struct PromoModule {
    pub coupon_code_service: Arc<CouponCodeService>,
    pub coupon_redemption_service: Arc<CouponRedemptionService>,
    pub loyalty_program_service: Arc<LoyaltyProgramService>,
    pub loyalty_point_entry_service: Arc<LoyaltyPointEntryService>,
    pub pricing_rule_service: Arc<PricingRuleService>,
    pub promo_bundle_service: Arc<PromoBundleService>,
    pub promo_bundle_component_service: Arc<PromoBundleComponentService>,
}

impl PromoModule {
    /// Create a new module builder
    pub fn builder() -> PromoModuleBuilder {
        PromoModuleBuilder::new()
    }

    /// Mount ALL generated CRUD endpoints (12 per entity) with NO domain
    /// validation — the fully **unguarded** surface. A well-formed request can
    /// create invalid rows or soft-delete a referenced master out from under its
    /// dependents. Prefer a guarded composition (read + validated writes) for any
    /// real deployment; use this only in trusted/admin/seeding contexts.
    pub fn all_crud_routes(&self) -> Router {
        use presentation::http::{
            create_coupon_code_routes,
            create_coupon_redemption_routes,
            create_loyalty_program_routes,
            create_loyalty_point_entry_routes,
            create_pricing_rule_routes,
            create_promo_bundle_routes,
            create_promo_bundle_component_routes,
        };

        Router::new()
            .merge(create_coupon_code_routes(self.coupon_code_service.clone()))
            .merge(create_coupon_redemption_routes(self.coupon_redemption_service.clone()))
            .merge(create_loyalty_program_routes(self.loyalty_program_service.clone()))
            .merge(create_loyalty_point_entry_routes(self.loyalty_point_entry_service.clone()))
            .merge(create_pricing_rule_routes(self.pricing_rule_service.clone()))
            .merge(create_promo_bundle_routes(self.promo_bundle_service.clone()))
            .merge(create_promo_bundle_component_routes(self.promo_bundle_component_service.clone()))
    }

    /// Deprecated alias for [`Self::all_crud_routes`]. `routes()` reads like
    /// "the routes" but mounts UNVALIDATED generic CRUD on every entity — a naive
    /// mount exposes unguarded writes. Compose a guarded router (read + validated
    /// writes) for production, or call `all_crud_routes()` to opt into the full
    /// unguarded surface explicitly.
    #[deprecated(note = "mounts unvalidated generic CRUD on every entity; compose a guarded router for production, or call all_crud_routes() for the intentional full/unguarded surface")]
    pub fn routes(&self) -> Router {
        self.all_crud_routes()
    }
}

